const adr = $('ADR Lookup').item.json;
const calc = $input.item.json;
const substance = adr.results?.[0] ?? {};

const lines = [
  `=== DANGEROUS GOODS CHECK ==="`,
  ``,
  `Substance: UN ${substance.un_number} — ${substance.proper_shipping_name}`,
  `Class: ${substance.class} | Packing Group: ${substance.packing_group}`,
  `Labels: ${substance.labels} | Tunnel Code: ${substance.tunnel_restriction_code}`,
  `Transport Category: ${substance.transport_category}`,
  `Limited Quantity: ${substance.limited_quantity}`,
  ``,
  `--- Exemption Calculation (ADR 1.1.3.6) ---`,
  `Quantity: ${calc.items?.[0]?.quantity ?? 'N/A'} kg/L`,
  `Points: ${calc.total_points} / ${calc.threshold}`,
  ``,
  calc.exempt
    ? `✅ EXEMPT — Load qualifies for 1.1.3.6 limited quantity exemption.`
    : `❌ NOT EXEMPT — Full ADR compliance required.`,
  ``,
  `Message: ${calc.message}`,
];

if (calc.warnings?.length) {
  lines.push(``, `Warnings:`);
  calc.warnings.forEach(w => lines.push(`  ⚠ ${w}`));
}

return [{
  json: {
    summary: lines.join('\n'),
    exempt: calc.exempt,
    un_number: substance.un_number,
    substance_name: substance.proper_shipping_name,
    hazard_class: substance.class,
    total_points: calc.total_points,
    threshold: calc.threshold
  }
}];
